import React from "react";

import { Button, Tooltip } from "@mui/material";
import EditIcon from "@mui/icons-material/Edit";
import PersonIcon from "@mui/icons-material/Person";
import { useNavigate } from "@tanstack/react-router";
import { PageContainer } from "@/components/PageContainer";
import { StatusMessage } from "@/components/StatusMessage";
import { ProfileDisplay } from "./ProfileDisplay";
import { CallStatus } from "@/types/api.types";
import { useProfilesStore, initialStateData, StateData } from "@/store";
import { ProfileResult } from "@/types/profile.types";
import { ApiComponentStateManager, ApiGlobalStateManager } from "@/lib/api-state";
import { ProfileServices, ProfileServicesError } from "@/api";
import { Pathname } from "@/constants/Routes";

interface ProfileViewProps {
    profileId?: string;
}

export const ProfileView: React.FC<ProfileViewProps> = ({ profileId: propProfileId }) => {
    const { profileState, setProfileState } = useProfilesStore();
    const navigate = useNavigate();
    const [isOtherProfile, setIsOtherProfile] = React.useState<StateData<ProfileResult>>(initialStateData<ProfileResult>());
    const [otherProfileId, setOtherProfileId] = React.useState<string>("");
    const hasFetchedRef = React.useRef<boolean>(false);

    React.useEffect(() => {
        if (propProfileId) {
            setOtherProfileId(propProfileId);
            if (!hasFetchedRef.current) {
                hasFetchedRef.current = true;
                ApiComponentStateManager(ProfileServices.GetProfileById(propProfileId), setIsOtherProfile);
            }
        }
        else if (!profileState.data.id && !hasFetchedRef.current) {
            hasFetchedRef.current = true;
            ApiGlobalStateManager(ProfileServices.GetProfile(), setProfileState);
        }
    }, [propProfileId]);

    const isOwnProfile = !otherProfileId && profileState.status === CallStatus.Success && !!profileState.data.id;
    const headerTitle = otherProfileId ? 'Profile' : 'My profile';
    const headerSubtitle = otherProfileId
        ? 'Public details for this member.'
        : 'Your full profile, including contact, education and work info, with per-section visibility controls.';

    const editAction = isOwnProfile ? (
        <Tooltip title="Edit profile">
            <Button
                variant="contained"
                size="small"
                startIcon={<EditIcon fontSize="small" />}
                onClick={() => navigate({ to: Pathname.Profile_Edit, search: {} as any } as any)}
                sx={{ textTransform: 'none', borderRadius: 2 }}
            >
                Edit
            </Button>
        </Tooltip>
    ) : undefined;

    return (
        <PageContainer
            icon={<PersonIcon color="primary" />}
            title={headerTitle}
            subtitle={headerSubtitle}
            action={editAction}
        >
            {otherProfileId ? (
                isOtherProfile.status === CallStatus.Success && isOtherProfile.data.id ? (
                    <ProfileDisplay {...isOtherProfile.data} />
                ) : (
                    <StatusMessage
                        notStartedMessage="Loading profile..."
                        failureMessage={ProfileServicesError.GetProfileError(isOtherProfile.httpStatus)}
                        currentStatus={isOtherProfile.status}
                        correlationId={isOtherProfile.correlationId}
                    />
                )
            ) : (
                profileState.status === CallStatus.Success && profileState.data.id ? (
                    <ProfileDisplay {...profileState.data} />
                ) : (
                    <StatusMessage
                        notStartedMessage="Loading your profile..."
                        failureMessage={ProfileServicesError.GetProfileError(profileState.httpStatus)}
                        currentStatus={profileState.status}
                        correlationId={profileState.correlationId}
                    />
                )
            )}
        </PageContainer>
    );
};

