import React from "react";
import { Box, Card, CardContent, Chip, Divider, Stack, Typography, Button } from "@mui/material";
import ContactMailIcon from '@mui/icons-material/ContactMail';
import WorkIcon from '@mui/icons-material/Work';
import SchoolIcon from '@mui/icons-material/School';
import BadgeIcon from '@mui/icons-material/Badge';
import VisibilityIcon from '@mui/icons-material/Visibility';
import VisibilityOffIcon from '@mui/icons-material/VisibilityOff';
import PreviewIcon from '@mui/icons-material/Preview';
import { GetUserEmail } from "@/utils/token";
import { ProfileResult } from "@/types/profile.types";
import { ProfileInfoDialog } from '@/components/ProfileInfoDialog';
import { compactChipSx } from '@/constants/ThemeConstants';

const VisibilityChip: React.FC<{ visible: boolean }> = ({ visible }) => (
    <Chip
        icon={visible ? <VisibilityIcon sx={{ fontSize: '0.85rem' }} /> : <VisibilityOffIcon sx={{ fontSize: '0.85rem' }} />}
        label={visible ? "Visible to members" : "Not visible to anyone"}
        size="small"
        color={visible ? 'success' : 'default'}
        variant="outlined"
        sx={{ ...compactChipSx }}
    />
);

interface SectionProps {
    icon: React.ReactNode;
    title: string;
    visible: boolean;
    children: React.ReactNode;
}

const Section: React.FC<SectionProps> = ({ icon, title, visible, children }) => (
    <Card variant="outlined" sx={{ borderRadius: 2 }}>
        <CardContent sx={{ '&:last-child': { pb: 2 } }}>
            <Stack
                direction={{ xs: 'column', sm: 'row' }}
                spacing={1}
                sx={{ alignItems: { xs: 'flex-start', sm: 'center' }, justifyContent: 'space-between', mb: 1.5 }}
            >
                <Stack direction="row" spacing={1.25} sx={{ alignItems: 'center' }}>
                    <Box sx={{ color: 'primary.main', display: 'inline-flex' }}>{icon}</Box>
                    <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>{title}</Typography>
                </Stack>
                <VisibilityChip visible={visible} />
            </Stack>
            <Divider sx={{ mb: 1.5 }} />
            <Stack spacing={1}>{children}</Stack>
        </CardContent>
    </Card>
);

const Field: React.FC<{ label: string; value?: React.ReactNode }> = ({ label, value }) => (
    <Stack
        direction={{ xs: 'column', sm: 'row' }}
        spacing={{ xs: 0, sm: 1.5 }}
        sx={{ alignItems: { xs: 'flex-start', sm: 'baseline' } }}
    >
        <Typography
            variant="body2"
            color="text.secondary"
            sx={{ minWidth: { sm: 120 }, fontWeight: 500 }}
        >
            {label}
        </Typography>
        <Typography variant="body2" color="text.secondary" sx={{ wordBreak: 'break-word' }}>
            {value && value !== '' ? value : <Box component="span" sx={{ color: 'text.disabled', fontStyle: 'italic' }}>Not set</Box>}
        </Typography>
    </Stack>
);

export const ProfileDisplay = (props: ProfileResult) => {
    const [previewOpen, setPreviewOpen] = React.useState(false);
    const otherJnvText = Array.isArray(props.otherJnvNames) && props.otherJnvNames.length > 0
        ? props.otherJnvNames.join(', ')
        : '';
    const associationText = [props.firstJnvName, otherJnvText].filter(Boolean).join(', ');
    const tenureText = `${props.entryYear} - ${props.exitYear === 0 ? "Present" : props.exitYear}`;

    return (
        <>
            <Stack spacing={2}>
                <Section icon={<BadgeIcon />} title="Navodaya Info" visible>
                    <Field label="Name" value={props.name} />
                    <Field label={props.profileType ?? 'Tenure'} value={tenureText} />
                    <Field label="Association" value={associationText} />
                </Section>

                <Section icon={<ContactMailIcon />} title="Contact Info" visible={props.isContactInfoVisible}>
                    <Field label="Email" value={props.email ?? GetUserEmail()} />
                    <Field label="Phone" value={props.phone} />
                    <Field label="Location" value={props.location} />
                </Section>

                <Section icon={<SchoolIcon />} title="Education Info" visible={props.isHigherEducationInfoVisible}>
                    <Field label="University" value={props.university} />
                    <Field label="Degree" value={props.degree} />
                </Section>

                <Section icon={<WorkIcon />} title="Work Info" visible={props.isEmploymentInfoVisible}>
                    <Field label="Job Title" value={props.jobTitle} />
                    <Field label="Organisation" value={props.organisation} />
                </Section>

                <Box sx={{ display: 'flex', justifyContent: 'center', pt: 0.5 }}>
                    <Button
                        onClick={() => setPreviewOpen(true)}
                        startIcon={<PreviewIcon />}
                        size="small"
                        sx={{ textTransform: 'none', fontWeight: 500 }}
                    >
                        Preview how others see my profile
                    </Button>
                </Box>
            </Stack>

            <ProfileInfoDialog
                open={previewOpen}
                profileId={props.id}
                mode="public"
                onClose={() => setPreviewOpen(false)}
            />
        </>
    );
};

